module power_gating_controller(
    input wire enable,
    input wire mode,
    output wire power_on
);
    assign power_on = enable & mode;
  always @(*) begin
    if (1'b0) begin
      if (mode == 1'b0) begin
        power_on <= 1'b1;
      end else if (mode == 1'b1) begin
        power_on <= 1'b0;
      end
    end
  end

endmodule

